-- Schema migrations (idempotent, continue-on-error=true handles reruns)
ALTER TABLE player ALTER COLUMN arena_energy DOUBLE NOT NULL DEFAULT 120;
ALTER TABLE player ALTER COLUMN world_energy DOUBLE NOT NULL DEFAULT 120;
ALTER TABLE player ADD COLUMN IF NOT EXISTS last_blacksmith_spin TIMESTAMP;
ALTER TABLE player ADD COLUMN IF NOT EXISTS pending_spin_material_id BIGINT;
ALTER TABLE player ADD COLUMN IF NOT EXISTS pending_spin_qty INT NOT NULL DEFAULT 0;
CREATE TABLE IF NOT EXISTS team_setup (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    player_id BIGINT NOT NULL,
    setup_index INT NOT NULL,
    name VARCHAR(30) NOT NULL,
    is_active BOOLEAN NOT NULL DEFAULT FALSE
);
CREATE TABLE IF NOT EXISTS team_setup_slot (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    setup_id BIGINT NOT NULL,
    slot_number INT NOT NULL,
    hero_id BIGINT,
    summon_id BIGINT
);
CREATE TABLE IF NOT EXISTS team_setup_hero_equipment (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    setup_id BIGINT NOT NULL,
    hero_id BIGINT NOT NULL,
    slot_number INT NOT NULL,
    item_template_id BIGINT,
    ability_template_id BIGINT
);
CREATE TABLE IF NOT EXISTS password_reset_token (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    token VARCHAR(255) NOT NULL UNIQUE,
    player_id BIGINT NOT NULL,
    expires_at TIMESTAMP NOT NULL,
    used_at TIMESTAMP
);
ALTER TABLE player ADD COLUMN IF NOT EXISTS banned BOOLEAN DEFAULT FALSE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS chat_sound_enabled BOOLEAN DEFAULT TRUE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS extra_lineup_gold_purchased BOOLEAN DEFAULT FALSE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS extra_lineup_diamonds_purchased BOOLEAN DEFAULT FALSE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS energy_plus_purchased BOOLEAN DEFAULT FALSE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS hero_plus_capacity_purchased BOOLEAN DEFAULT FALSE;
ALTER TABLE player ADD COLUMN IF NOT EXISTS capacity_plus_count INT DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS stat_purchase_count INT DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_pa DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_mp DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_dex DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_elem DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_mana DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS bonus_stam DOUBLE DEFAULT 0;
ALTER TABLE hero ADD COLUMN IF NOT EXISTS capacity_override INT;
ALTER TABLE equipped_item ALTER COLUMN hero_id SET NULL;
ALTER TABLE equipped_item ALTER COLUMN slot_number SET NULL;
ALTER TABLE equipped_item ADD COLUMN IF NOT EXISTS player_id BIGINT;
ALTER TABLE equipped_ability ALTER COLUMN hero_id SET NULL;
ALTER TABLE equipped_ability ADD COLUMN IF NOT EXISTS player_id BIGINT;
ALTER TABLE equipped_ability ADD COLUMN IF NOT EXISTS slot_number INT;

-- ── Deduplicate existing rows from historical non-idempotent seeding ────────
-- These UPDATE/DELETE statements are no-ops when there are no duplicates.
-- They run every restart but are safe due to continue-on-error=true.

-- 1. Fix equipped_item rows pointing to duplicate item_template rows, then delete dupes
UPDATE equipped_item SET item_template_id = (
    SELECT MIN(t2.id) FROM item_template t2
    WHERE t2.name = (SELECT t.name FROM item_template t WHERE t.id = equipped_item.item_template_id)
) WHERE item_template_id NOT IN (SELECT MIN(id) FROM item_template GROUP BY name);
DELETE FROM item_template WHERE id NOT IN (SELECT MIN(id) FROM item_template GROUP BY name);

-- 2. Fix equipped_ability rows pointing to duplicate ability_template rows, then delete dupes
UPDATE equipped_ability SET ability_template_id = (
    SELECT MIN(a2.id) FROM ability_template a2
    WHERE a2.name = (SELECT a.name FROM ability_template a WHERE a.id = equipped_ability.ability_template_id)
    AND a2.hero_template_id = (SELECT a.hero_template_id FROM ability_template a WHERE a.id = equipped_ability.ability_template_id)
) WHERE ability_template_id NOT IN (SELECT MIN(id) FROM ability_template GROUP BY name, hero_template_id);
DELETE FROM ability_template WHERE id NOT IN (SELECT MIN(id) FROM ability_template GROUP BY name, hero_template_id);

-- 3. Fix hero rows pointing to duplicate hero_template rows, then delete dupes
UPDATE hero SET template_id = (
    SELECT MIN(t2.id) FROM hero_template t2
    WHERE t2.name = (SELECT t.name FROM hero_template t WHERE t.id = hero.template_id)
) WHERE template_id NOT IN (SELECT MIN(id) FROM hero_template GROUP BY name);
DELETE FROM hero_template WHERE id NOT IN (SELECT MIN(id) FROM hero_template GROUP BY name);

-- 4a. Fix team_setup_hero_equipment rows pointing to duplicate item/ability template rows
UPDATE team_setup_hero_equipment SET item_template_id = (
    SELECT MIN(t2.id) FROM item_template t2
    WHERE t2.name = (SELECT t.name FROM item_template t WHERE t.id = team_setup_hero_equipment.item_template_id)
) WHERE item_template_id IS NOT NULL
  AND item_template_id NOT IN (SELECT MIN(id) FROM item_template GROUP BY name);

UPDATE team_setup_hero_equipment SET ability_template_id = (
    SELECT MIN(a2.id) FROM ability_template a2
    WHERE a2.name = (SELECT a.name FROM ability_template a WHERE a.id = team_setup_hero_equipment.ability_template_id)
    AND a2.hero_template_id = (SELECT a.hero_template_id FROM ability_template a WHERE a.id = team_setup_hero_equipment.ability_template_id)
) WHERE ability_template_id IS NOT NULL
  AND ability_template_id NOT IN (SELECT MIN(id) FROM ability_template GROUP BY name, hero_template_id);

-- 4. Fix summon rows pointing to duplicate summon_template rows, then delete dupes
UPDATE summon SET template_id = (
    SELECT MIN(t2.id) FROM summon_template t2
    WHERE t2.name = (SELECT t.name FROM summon_template t WHERE t.id = summon.template_id)
) WHERE template_id NOT IN (SELECT MIN(id) FROM summon_template GROUP BY name);
DELETE FROM summon_template WHERE id NOT IN (SELECT MIN(id) FROM summon_template GROUP BY name);

