-- ═══════════════════════════════════════════════════════════════════════════
-- BLACKSMITH SYSTEM
-- ═══════════════════════════════════════════════════════════════════════════

-- ── New tables ──────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS material_template (
    id          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name        VARCHAR(100) NOT NULL UNIQUE,
    icon_key    VARCHAR(50),
    tier        INT NOT NULL,
    category    VARCHAR(50),
    description VARCHAR(255)
);

CREATE TABLE IF NOT EXISTS player_material (
    id                   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    player_id            BIGINT NOT NULL,
    material_template_id BIGINT NOT NULL,
    quantity             INT NOT NULL DEFAULT 0,
    CONSTRAINT uq_player_material UNIQUE (player_id, material_template_id)
);

CREATE TABLE IF NOT EXISTS weapon_recipe (
    id               BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    item_template_id BIGINT NOT NULL UNIQUE
);

CREATE TABLE IF NOT EXISTS weapon_recipe_ingredient (
    id                   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    recipe_id            BIGINT NOT NULL,
    material_template_id BIGINT NOT NULL,
    quantity             INT NOT NULL
);

CREATE TABLE IF NOT EXISTS material_recipe (
    id                          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    output_material_template_id BIGINT NOT NULL UNIQUE,
    output_quantity             INT NOT NULL DEFAULT 1
);

CREATE TABLE IF NOT EXISTS material_recipe_ingredient (
    id                   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    material_recipe_id   BIGINT NOT NULL,
    material_template_id BIGINT NOT NULL,
    quantity             INT NOT NULL
);

-- ── ALTER weapon_recipe and material_recipe for craft times ────────────────
ALTER TABLE weapon_recipe   ADD COLUMN IF NOT EXISTS craft_hours INT NOT NULL DEFAULT 24;
ALTER TABLE material_recipe ADD COLUMN IF NOT EXISTS craft_hours INT NOT NULL DEFAULT 2;

-- Set craft times by weapon tier
UPDATE weapon_recipe SET craft_hours = 36  WHERE item_template_id IN (SELECT id FROM item_template WHERE weapon_tier = 'COMMON');
UPDATE weapon_recipe SET craft_hours = 96  WHERE item_template_id IN (SELECT id FROM item_template WHERE weapon_tier = 'EPIC');
UPDATE weapon_recipe SET craft_hours = 216 WHERE item_template_id IN (SELECT id FROM item_template WHERE weapon_tier = 'LEGENDARY');

-- Set craft times by output material tier
UPDATE material_recipe SET craft_hours = 4   WHERE output_material_template_id IN (SELECT id FROM material_template WHERE tier = 2);
UPDATE material_recipe SET craft_hours = 24  WHERE output_material_template_id IN (SELECT id FROM material_template WHERE tier = 3);
UPDATE material_recipe SET craft_hours = 72  WHERE output_material_template_id IN (SELECT id FROM material_template WHERE tier = 4);
UPDATE material_recipe SET craft_hours = 144 WHERE output_material_template_id IN (SELECT id FROM material_template WHERE tier = 5);

-- ── ALTER item_template for Blacksmith weapon support ──────────────────────
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS is_craftable  BOOLEAN DEFAULT FALSE;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS weapon_tier   VARCHAR(20);
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS icon_key      VARCHAR(50);
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_name    VARCHAR(100);
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_mana_cost INT DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_trigger VARCHAR(20);
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_chance  DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_pa   DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_mp   DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_dex  DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_elem DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_mana DOUBLE DEFAULT 0;
ALTER TABLE item_template ADD COLUMN IF NOT EXISTS spell_bonus_stam DOUBLE DEFAULT 0;

