-- ═══════════════════════════════════════════════════════════════════════════════
-- WEAPON SPELLS (multi-spell system)
-- ═══════════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS weapon_spell (
    id               BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    item_template_id BIGINT NOT NULL,
    spell_name       VARCHAR(100) NOT NULL,
    spell_mana_cost  INT NOT NULL DEFAULT 0,
    spell_trigger    VARCHAR(30),
    spell_chance     DOUBLE NOT NULL DEFAULT 0,
    -- Meta
    max_usages       INT NOT NULL DEFAULT 0,
    lasts_turns      INT NOT NULL DEFAULT 0,
    affects_opponent BOOLEAN NOT NULL DEFAULT FALSE,
    turn_threshold   INT NOT NULL DEFAULT 0,
    -- Base stats
    spell_bonus_pa   DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_mp   DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_dex  DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_elem DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_mana DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_stam DOUBLE NOT NULL DEFAULT 0,
    -- Combat modifiers
    spell_bonus_attack                 DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_magic_proficiency      DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_spell_mastery          DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_spell_activation       DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_dex_proficiency        DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_dex_posture            DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_crit_chance            DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_crit_damage            DOUBLE NOT NULL DEFAULT 0,
    -- Progression
    spell_bonus_exp_bonus              DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_gold_bonus             DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_item_discovery         DOUBLE NOT NULL DEFAULT 0,
    -- Immunities
    spell_bonus_physical_immunity      DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_magic_immunity         DOUBLE NOT NULL DEFAULT 0,
    spell_bonus_dex_evasiveness        DOUBLE NOT NULL DEFAULT 0
);

-- Helper macro: insert spell only if not already present for that weapon
-- Format: INSERT INTO weapon_spell ... SELECT id,'SpellName',... FROM item_template WHERE name='X' AND NOT EXISTS(...)

-- ── EPIC Weapon Spells ───────────────────────────────────────────────────────
-- Ares' War Cleaver (1 existing → add 1 more → 2 total)
INSERT INTO weapon_spell (item_template_id,spell_name,spell_mana_cost,spell_trigger,spell_chance,spell_bonus_pa,spell_bonus_mp,spell_bonus_dex,spell_bonus_elem,spell_bonus_mana,spell_bonus_stam) SELECT id,'Wrath of Ares',8,'ATTACK',0.25,5,0,0,0,0,0 FROM item_template WHERE name='Ares'' War Cleaver' AND NOT EXISTS(SELECT 1 FROM weapon_spell WHERE item_template_id=(SELECT id FROM item_template WHERE name='Ares'' War Cleaver') AND spell_name='Wrath of Ares');
